std::string markdownToHtmlInternal(const std::string& markdown) {
    std::stringstream stream(markdown);
    std::string paragraph = "";
    bool inParagraph = false;

    while (!stream.eof()) {
        std::string line = stream.getline();

        // Check if the line is in a paragraph.
        if (inParagraph) {
            // Add a start tag for the paragraph.
            paragraph += "<p>";
        }

        // Add the line to the paragraph.
        paragraph += line;

        // Check if the line is the start of a new paragraph.
        if (!inParagraph) {
            // Add a end tag for the paragraph.
            paragraph += "</p>";
        }

        // Keep track of whether the current line is in a paragraph.
        inParagraph = true;
    }

    // Add a closing tag for the paragraph.
    paragraph += "</p>";

    return paragraph;
}
